{
  "formal_minutes": {
    "meeting_meta": {
      "project_code": "PUBLIC_MEETING_SMOKE",
      "meeting_title": "UI Theme Package Release Readiness",
      "participants": ["Minjun", "Seoyeon", "Doyun", "Hara"]
    },
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트 통과 시 금요일 15:00 KST에 공개 릴리스",
        "conditions": ["스모크 테스트 통과"]
      },
      {
        "topic": "packageName 불일치 대응 원칙",
        "decision": "불일치 발생 시 먼저 패키지 설정(계약) 확인, 계약 자체가 잘못된 경우에만 스크립트 검토"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "result": "거절"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표(확정 릴리스 일정 아님)"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토",
        "note": "목요일까지 가능하면 진행 제안 있었으나, 소유자 미지정으로 확정 실행 계획 아님"
      },
      {
        "item": "수요일 스트레치 목표를 릴리스 노트에 기재할지 여부",
        "note": "결론 없음"
      }
    ],
    "risks": [
      {
        "risk": "생성된 tarball 경로 오류",
        "impact": "릴리스 지연 가능"
      },
      {
        "risk": "README 설치 단계 최신성 부족",
        "impact": "릴리스 노트가 사용자에게 오해를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "미해결"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?",
        "status": "미해결"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 점검",
      "due": "미지정",
      "status": "확정(선행조건 존재)",
      "source_certainty": "high"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계 검토(목요일까지 가능하면)",
      "due": "목요일(권고/희망)",
      "status": "제안(미확정)",
      "source_certainty": "medium"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun 스모크 테스트 결과 통과/실패 여부 확인",
      "Doyun의 failure triage note 작성 완료 여부 확인",
      "스모크 결과 게시 이후 Hara의 tarball 경로 점검 결과 확인",
      "최종 릴리스 승인 권한자 확정",
      "릴리스 노트에 수요일 내부 스트레치 목표 기재 여부 결정"
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "명시되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 fixture에 없는 사실은 추가하지 않는다.",
    "확정/거절/스트레치/리스크/오픈질문을 혼합하지 않고 분리 기록한다.",
    "소유자 또는 마감이 명시되지 않은 항목은 '미지정'으로 유지한다.",
    "조건부 결정은 조건(예: 스모크 테스트 통과)을 함께 기록한다.",
    "명시적 비사실(고객, 예산, 보안, 장애, 법무)은 사실처럼 서술하지 않는다."
  ]
}
